var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하, 하하…… 카린 양?","JPN":"ハ、ハハ……カリンさん？","ENG":"Ha, ha ha... Karin?","TWN":"哈，哈哈……卡琳？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아무리 작전이라고 해도, 이건 좀 아닌 거 같지 않아요?","JPN":"いくら作戦だといっても、これは違うんじゃないですかね。","ENG":"Even for an operation, isn't this a bit too risky?","TWN":"雖說是作戰，但好像哪裡不太對？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"괜히 이런 곳에 있다가, 저 고치를 자극해서 좋을 게 없다고 생각하는데요?","JPN":"こんなところに来てあの繭を刺激しても、何もいいことないですよ？","ENG":"If we lounge around here, we might end up provoking that cocoon.","TWN":"我覺得我們待在這裡會刺激到那個繭，這對我們來說沒有任何好處。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저도 시영 씨 의견에 동의해요.","JPN":"私もシノンさんの意見に同意します。","ENG":"I agree with you, Shiyoung.","TWN":"我很贊成你的想法。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그렇죠? 그럼 어서 여기서 벗어나자구요.","JPN":"ですよね？　それじゃあ、早くここから出ましょう。","ENG":"Right? Okay, then let's get out of here.","TWN":"是吧？那我們趕緊離開這裡吧？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"거절하겠어요, 시영 씨. 왜냐하면…… 여기에 있다는 정보를 얻었거든요.","JPN":"お断りします、シノンさん。なぜなら……ここに存在するという情報を手に入れましたので。","ENG":"I refuse, Shiyoung. Because... I received intel, that it is here.","TWN":"我拒絕。因為……據我得到情報所描述，東西就在這個地方。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"있다고요? 뭐가요? 설마 유령이?","JPN":"存在する？　何がですか？　もしかして、幽霊？","ENG":"It? What's it? A ghost?","TWN":"就在這個地方？什麼東西？莫非是幽靈？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"유, 유령!?","JPN":"ゆ、幽霊！？","ENG":"A-a ghost?!","TWN":"幽，幽靈？！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"어, 어디…… 어디에요!?","JPN":"ど、どこ……どこですか！？","ENG":"W-where... Where is it?!","TWN":"在，在……在哪裡啊？！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아, 아니야! 이 세상에 유령 같은 건 없다고요! 장난치지 마세요, 시영 씨!","JPN":"い、いいえ！　この世に幽霊なんていません！　からかわないでください、シノンさん！","ENG":"N-no! There's no such thing as ghosts! Stop joking around, Shiyoung!","TWN":"不，不！這個世界上才沒有幽靈！你別開玩笑了，時雨！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아무튼 제가 말하려던 건, 이곳 어딘가 소원을 이루어 주는 <color=#ffd34c>아티팩트</color>가 있다는 제보를 받았기 때문이에요.","JPN":"とにかく、私が言おうとしていたのは、ここのどこかに願いを叶えてくれる<color=#ffd34c>アーティファクト</color>があるという情報を得たからです。","ENG":"Well, what I was trying to say was that there's an <color=#ffd34c>Artifact</color> that grants wishes somewhere around here.","TWN":"總之，我想說的是，我得到消息說在這地方的某處，有可以實現願望的<color=#ffd34c>人造神器</color>。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"소원을 이루어 준다고요?","JPN":"願いを叶えてくれる？","ENG":"Grants wishes?","TWN":"可以實現願望？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"에이, 말도 안 돼. 그런 게 있으면 우리 세계가 이렇게 막장이 되었을 리 없잖아요.","JPN":"またまた。あり得ません。そんなものがあったら、私たちの世界はこんなに追い詰められてませんよ。","ENG":"No way. If that really existed, our world would never be this disastrous.","TWN":"哈哈！騙人的吧？要是真有那種東西，那我們的世界也不至於變得這麼糟糕。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"네. 하지만 충분히 검증해볼 필요는 있어요.","JPN":"はい。ですが、検証してみる必要はあると思います。","ENG":"Right, but it's still worth investigating.","TWN":"嗯，不過，我們需要充分驗證一下。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"우리가 찾는 아티팩트에는 <color=#ffd34c>원숭이 손</color>이라는 이름이 붙어 있다고 하니까요.","JPN":"私たちが探しているアーティファクトには、<color=#ffd34c>サルの手</color>という名前がついているらしいですから。","ENG":"It is said that the Artifact we're looking for is called the <color=#ffd34c>Monkey's Paw</color>.","TWN":"我們要找的人造神器叫作<color=#ffd34c>猴爪</color>。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"네? <color=#ffd34c>원숭이 손</color>?","JPN":"はい？　<color=#ffd34c>サルの手</color>？","ENG":"Huh? <color=#ffd34c>Monkey's Paw</color>?","TWN":"什麼？<color=#ffd34c>猴爪</color>？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하하. 왠지 소원을 들어주긴 하는데, 요상한 방식으로 이루어 줄 것 같은 이름인데요?","JPN":"ハハ。なんだか願いを叶えてはくれるけど、変な形で叶えてくれそうな名前ですね。","ENG":"Ha ha. That sounds like a name that would grant wishes, but in a twisted way.","TWN":"哈哈，感覺雖然能實現願望，但聽起來似乎會用奇怪的方法實現？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"시영 씨 말이 맞아요. 애초에 그런 효과 때문에 원숭이 손이라는 이름이 붙은 거죠.","JPN":"おっしゃるとおりです。そもそも、そんな効果があるからサルの手という名前がついたわけです。","ENG":"You're right. That's why it's called a Monkey's Paw in the first place.","TWN":"你說的沒錯。就是因為那種效果，所以才會將它取名為猴爪。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"실제로 아티팩트가 어떻게 생겼는 지, 그게 어떤 물건인지는 아무도 모르지만요.","JPN":"実際にアーティファクトがどんな形をしていて、どんなものなのかは誰も知らないそうですが。","ENG":"But no one knows what the Artifact looks like or what it actually is.","TWN":"實際上，誰也不知道這個人造神器長什麼樣子，是一個什麼樣的東西。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"네? 그럼 어떻게 생긴 지도 모르는 물건을 찾는다는 말이에요?","JPN":"はい？　どんな形かも知らないものをどうやって探すんですか？","ENG":"What? Then we're looking for something, and we don't even know what it looks like?","TWN":"什麼？我們要怎麼找一個不知道長怎樣的東西？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"믿기 힘든 이야기지만, 트레져헌터들 사이에서의 소문에 따르면, 아티팩트에는 <color=#ffd34c>보증서</color>가 같이 발굴되는 경우가 있다고 해요.","JPN":"信じ難い話ですけど、トレジャーハンターの間で流れてる噂によると、アーティファクトは<color=#ffd34c>保証書</color>と一緒に発掘される場合があるそうです。","ENG":"Believe it or not, according to the rumors among treasure hunters, Artifacts sometimes come with a <color=#ffd34c>warranty certificate</color>.","TWN":"雖然令人難以置信，但據貪婪的淘金者之間的傳聞，有時候人造神器會和<color=#ffd34c>保證書</color>一同被挖掘出來。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그 보증서에는 아티팩트의 명칭과 효과…… 그리고 뭐였더라?","JPN":"その保証書には、アーティファクトの名称と効果……それから、ええと。","ENG":"That warranty is said to contain the Artifact's name, effect, and... what was it?","TWN":"保證書上寫著人造神器的名稱和效果……還有什麼來著？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"<color=#ffd34c>여기까지 도달한 걸 축하한다, 2등</color>이였던가? 아무튼 괴상한 메시지가 적혀 있다고 해요.","JPN":"<color=#ffd34c>ここまでよくたどり着いたな。おめでとう、2位</color>だったかな？　とにかく、変なメッセージが書いてあるらしいです。","ENG":"A weird message that reads, \\"<color=#ffd34c>Congratulations on coming in second,</color>\\" or something.","TWN":"好像是<color=#ffd34c>恭喜你到達這裡，第二名</color>之類的奇怪文字。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하하, 정말로 변변치 못한 정보네요, 그거.","JPN":"ハハ、本当につまらない情報ですね、それ。","ENG":"Ha ha, that's pretty useless information.","TWN":"哈哈，這個情報有點弱欸。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아무튼 이곳에 아티팩트가 있다면, 찾아볼 가치는 분명히 있어요.","JPN":"とにかくここにアーティファクトがあるなら、探してみる価値は十分あります。","ENG":"Whatever the case, if there's an Artifact here, it's definitely worth searching for.","TWN":"總之，如果這個地方真有人造神器，那還是很有尋找的價值。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이상한 방식으로 이루어 준다고는 하지만, 어쨌든 소원을 이루어 주는 강력한 아티팩트니까요.","JPN":"変な方法で叶えてくれるとは言いますけど、とにかく願いを叶えてくれる強力なアーティファクトですから。","ENG":"Even if it works in a twisted way, it's still a powerful Artifact that grants your wishes.","TWN":"雖說會用奇怪的方式實現願望，但總歸來說是可以實現願望的強大人造神器。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"엉뚱한 사람이 관리하는 것보다, 군에서 관리하는 편이 믿음직스럽겠죠.","JPN":"とんでもない人が管理するより、軍で管理した方が安心でしょう。","ENG":"It would be more trustworthy in the hands of the military, rather than in the hands of a stranger.","TWN":"與其交給莫名其妙的人來管理，還不如交由部隊更可靠些吧。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"어라라, 글쎄요?","JPN":"あれれ、どうでしょう？","ENG":"Oh, I'm not sure.","TWN":"呃呃，這個嘛？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"영화 같은 데서 보면, 꼭 카린 양 같은 고지식하고, 앞뒤 꽉 막힌 사람이 대의를 위한다면서 소원을 잘못 빌었다가 대참사가 일어나지 않나요?","JPN":"映画とかで見ると、カリンさんのような生真面目で融通の利かない人が、大儀のためと言いながら間違った願い事をして、大惨事が起きたりするじゃないですか。","ENG":"In movies, doesn't someone as strict and inflexible as you normally wish for the wrong thing \\"for the greater good\\" and end up causing a catastrophe?","TWN":"如果這是電影裡的劇情，像卡琳你這樣固執又死腦筋的人，會發生打著正義的旗幟許錯願望，導致發生悲劇的事情吧？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"설마, 그런 수상쩍은 물건으로 우리 세계의 멸망을 막아 달라는 소원을 빌지는 않겠죠?","JPN":"まさか、そんな怪しいもので私たちの世界の滅亡を止めてくれとか願ったりしないですよね？","ENG":"You wouldn't ask that sketchy thing for our world to be saved from doom, right?","TWN":"你不會用那個奇怪的東西，祈求阻止我們的世界滅亡吧？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"흥! 절 대체 어떻게 생각하는 거예요?","JPN":"フン！　いったい私をなんだと思っているのですか？","ENG":"Hmph! Who do you think I am?","TWN":"哼！你把我當成什麼人啦！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아티팩트 같은 엄청난 물건을 사적인 목적으로 쓸 생각은 없어요!","JPN":"アーティファクトのようなすごいものを、私的な目的に使うつもりはありません！","ENG":"I would never use something as great as an Artifact to fulfill my personal desires!","TWN":"我才不會把人造神器這麼厲害的東西用在私人目的上！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그리고 따지고 보면…… 저보다 시영 씨 같은 사람한테 아티팩트가 넘어가는 게 더 큰 일 아닌가요?","JPN":"それに考えてみたら……私よりシノンさんみたいな人の手にアーティファクトが渡る方がもっと危険なのでは？","ENG":"And realistically... wouldn't it be worse if the Artifact were to fall into the hands of someone like you, Shiyoung?","TWN":"而且真要說起來……把人造神器交給像你這樣的人反而更糟糕吧？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"네? 제가 왜요? 저 같이 욕심 없는 사람이 또 어디 있다고 그래요?","JPN":"はい？　どうしてですか？　私ほど欲のない人もいないと思いますが。","ENG":"Huh? What's wrong with me? I'm such a selfless person.","TWN":"我？我怎樣？還有人像我這樣無欲無求嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"혹시라도 제가 카린 양보다 먼저 아티팩트를 찾는다고 해도, 저어얼~대 먼저 쓸 생각이 없답니다?","JPN":"仮に私がカリンさんより先にアーティファクトを見つけたとしても、絶～対に先に使うつもりはないですよ？","ENG":"Even if I find the Artifact before you do, I would neeeeever use it first.","TWN":"就算我比卡琳先找到人造神器，我也絕～對不會擅自使用的喔？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그러고보니, 시영 씨. 아까 새끼 발톱이 아프다고 하셨죠?","JPN":"そういえば、シノンさん。さっき、足の小指の爪が痛いとか言っていましたよね？","ENG":"Oh, by the way, Shiyoung. You mentioned that your pinky toenail was hurting.","TWN":"不過時雨，你剛才不是說腳的小拇指痛嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"오늘은 이쯤하고 먼저 들어가시는 게 어때요?","JPN":"今日はこのくらいにして、先に帰ったらどうですか？","ENG":"How about you wrap it up here and head home?","TWN":"那今天就到此為止，要不你先回去？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"어라라, 그랬던가? 갑자기 괜찮아진 것 같은데요?","JPN":"あれれ、そうだったっけ？　急に治ったみたいですよ？","ENG":"Huh? Did I say that? It suddenly feels all right now!","TWN":"呃呃，是嗎？可是突然感覺好多了呢？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"으으…… 하필 이럴 때 침식체가!","JPN":"うう……よりによって、こんな時に侵食体が！","ENG":"Ugh... The timing of these C.O.s!","TWN":"呃……偏偏在這個時候出現侵蝕體！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"좋아요! 아무튼 지금은 힘을 합하도록 해요!","JPN":"仕方ありません！　とにかく、今は力を合わせましょう！","ENG":"Fine! Let's cooperate for now!","TWN":"很好！現在是我們合力的時候！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"카린 양? 아무래도 보증서가 딸려 있다는 힌트 하나로는 부족한 거 같은데…….","JPN":"カリンさん？　やっぱり保証書付きっていうヒントだけでは足りないと思うんですけど……","ENG":"Karin? The fact that it has a warranty certificate is not enough of a clue...","TWN":"卡琳？單憑人造神器有保證書這一個提示是遠遠不夠的……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"혹시, 저 몰래 힌트 한 두개 더 가지고 있는 거 아니에요?","JPN":"もしかして、私には内緒でヒントをもっと持ってたりしません？","ENG":"Are you hiding other clues or something?","TWN":"你是不是瞞著我？其實還有其他一、二個提示？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"좀 더 진지하게 작전에 임해줄 순 없어요? 이건 보물 찾기가 아니라고요!","JPN":"もっと真面目に作戦に取り掛かってもらえませんか？　これは宝探しではないんですよ！","ENG":"Would you take this operation more seriously? This isn't a treasure hunt!","TWN":"你就不能認真對待這次作戰嗎？這不是尋寶遊戲！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"보물찾기 맞는 거 같은데? 전 오히려 어렸을 때 생각나고 좋은데요?","JPN":"宝探しですよ、どう見ても。私はむしろ子どもの頃が思い出されて楽しいですけど？","ENG":"It sure seems like one. I like it. It reminds me of my childhood.","TWN":"就是尋寶遊戲吧？還讓我想起小時候，很開心呢？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그래서…… 이쯤 되면 말해줄 때도 되지 않았아요?","JPN":"それで……そろそろ言ってくれてもいいんじゃないですか？","ENG":"So... Isn't it about time you told me the truth?","TWN":"所以……現在可以告訴我了吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"카린 양이 만약 아티팩트를 손에 넣는다면, 어떤 소원을 빌고 싶으세요?","JPN":"もしカリンさんがアーティファクトを手に入れたら、何を願いたいんですか？","ENG":"If you find the Artifact, what wish are you going to make?","TWN":"如果卡琳你找到人造神器，你準備許什麼願望？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아까 듣기로는 개인적으로 쓸 생각은 없다고 했죠?","JPN":"さっきは個人的に使うつもりはないって言ってましたよね？","ENG":"You mentioned that you didn't want to use it for personal desires.","TWN":"你剛剛說，不會用於私人目的對吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L31_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"패스파인더 작전 이후, 저는 줄곧 생각해왔어요.","JPN":"パスファインダー作戦から、私はずっと考えていました。","ENG":"After Operation Pathfinder, I've been thinking.","TWN":"十字路口作戰之後，我就一直在想……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"시영 씨를 닮은 그 소년은 말했죠.","JPN":"シノンさんに似たあの少年が言っていましたよね。","ENG":"That boy, who looks like you, said something.","TWN":"那個和長得時雨很像的男孩說過的話。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"우리 세계와 그쪽 세계의 기술 격차는 <color=#ffd34c>관리국</color>이라는 조직 때문이라고…….","JPN":"私たちの世界とあちらの世界の技術の差は、<color=#ffd34c>管理局</color>という組織のせいだって……","ENG":"That the disparity between our world and their world's technology comes from an organization called <color=#ffd34c>the Administration</color>...","TWN":"我們世界和他們世界之所以有技術差距，是因為那個叫<color=#ffd34c>管理局</color>的組織……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"정말로 우리 세계에 관리국이라는 조직이 없어서 이런 결과에 도달한 거라면…….","JPN":"本当に私たちの世界に管理局という組織がなくてこんな結果に到達したのなら……","ENG":"If the state of our world is due to the absence of the Administration...","TWN":"如果我們世界真的是因為沒有管理局這種組織，才走向這種結局……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"반대로 지금이라도 우리 세계의 관리국 기술을 적용할 수 있다면 어떻게 될까요?","JPN":"逆に、今からでも私たちの世界に管理局の技術を適用できたならどうでしょうか？","ENG":"What would happen if we were to apply the Administration's technology to our world?","TWN":"那反過來，如果把管理局的技術應用在我們世界，那會怎麼樣呢？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"우리 세계의 멸망을 늦출……. 아니, 적어도 그때처럼 무력하게 주변 사람을 잃는 결과는 막을 수 있지 않을까요?","JPN":"私たちの世界の滅亡を遅らせる……いいえ、少なくともあの時のように、なす術もなく周りの人を失う結果だけは止められるのではないでしょうか？","ENG":"Maybe we could postpone the end of our world–or, rather, maybe we could prevent a future where we lose our beloved so helplessly.","TWN":"是不是就可以推遲我們世界的滅亡……不，至少可以阻止像那時一般無力地失去身邊人的結果吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"흐음……. 하지만 카린 양?","JPN":"ふーん……でも、カリンさん？","ENG":"Hmm, but Karin.","TWN":"唔……可是，卡琳？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"지난 작전에서 우리가 그 세계에 닿을 수 있었던 것은 순전히 우연이었잖아요.","JPN":"前の作戦で私たちがあの世界に行けたのは、偶然だったじゃないですか。","ENG":"It was merely a coincidence that we were able to reach that world in our previous operation.","TWN":"在上一次作戰中我們能到達那個世界，完全是因為巧合。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그 뒤로도 몇 번인가 저쪽 세계로 불려가긴 했지만…… 그건 저희의 의지가 아니었고요.","JPN":"その後も何度かあっちの世界に呼び出されていきましたけど……それは私たちの意志ではなかったですし。","ENG":"We did get sent to that world a few times after that, but... we had no say in that.","TWN":"在那之後，雖然又去過很多次那個世界……但那並不是因為我們自己的意志。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"시영 씨 말이 맞아요.","JPN":"シノンさんの言うとおりです。","ENG":"You're right.","TWN":"你說的沒錯。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"우리가 가진 기술과 자원으로는 다시 그 세계에 도달할 수 있다는 보장이 없어요.","JPN":"私たちが持っている技術と資源では、またあの世界に到達できるという保証がありません。","ENG":"With the technology and resources we possess, there's no guarantee of reaching that world again.","TWN":"我無法保證使用我們的技術和資源能再次達到那個世界。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그래서 이번에는 관점을 바꿔서 아티팩트의 힘을 빌려보려는 거죠.","JPN":"ですから、今回は視点を変えて、アーティファクトの力を借りてみようとしているのです。","ENG":"So this time, I'm attempting to approach it from a different angle and use the power of an Artifact.","TWN":"所以，這次我想換一個角度，就是借用人造神器的力量。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하하, 왠지 기술로 안 되니까, 주술로 빠지는 것 같은 느낌인데요.","JPN":"ハハ、技術ではうまくいかないから、だんだん呪術にハマっていきそうな感じですけど。","ENG":"Ha ha, it kinda sounds like you're falling back on voodoo since our technology wasn't enough.","TWN":"哈哈，聽起來像是技術不太行，就換魔法試試看呢。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하긴 뭐, 절벽에서 떨어지기 직전에 손에 잡히는 게 지푸라기뿐이라면, 일단 그거라도 잡고 봐야지 어쩌겠어요?","JPN":"確かにまあ、溺れる前に掴めるものが藁しかなかったら、とりあえずそれでも掴んどかないといけませんから。","ENG":"Well, desperate times call for desperate measures.","TWN":"不過也對，就把這當作是我們世界的救命稻草吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"혹시 또 모르는 거죠. 지푸라기인 줄 알고 잡았는데, 그게 동아줄일 수도 있잖아요?","JPN":"それに、藁だと思って掴んだものがロープかもしれませんしね？","ENG":"Who knows? This might actually be our way out.","TWN":"或許真能死馬當活馬醫？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"}}}},{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"후후. 오랜만에 마음이 통했네요, 시영 씨.","JPN":"ふふ。久しぶりに心が通じましたね、シノンさん。","ENG":"Hu hu. I'm glad we're in agreement.","TWN":"呵呵，久違的默契呢，時雨。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"}}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"음? 고양이?","JPN":"うん？　猫？","ENG":"Huh? A cat?","TWN":"嗯？小貓？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"어, 어어……? 시영 씨!! 저 고양이가 물고 있는 거 보여요!?","JPN":"え、ええっ……？　シノンさん！！　あの猫がくわえてるもの、見えますか！？","ENG":"Uh... Wait...! Shiyoung! Do you see that? In the cat's mouth!","TWN":"呃呃……？時雨！你有看到那個小貓叼著的東西嗎？！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"네? 무슨 반지 케이스 같은 거요?","JPN":"はい？　何か、指輪のケースみたいなものですか？","ENG":"Huh? That ring box-looking thing?","TWN":"嗯？看起來像是戒指盒的東西嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아뇨!! 저기, 끈으로 꼬리표가 달려있잖아요! 저게 아티팩트 보증서일 거예요!!","JPN":"いいえ！！　ほら、紐でタグが付いてるではないですか！　あれがアーティファクトの保証書のはずです！！","ENG":"No!! That tag, at the end of the string! That should be the warranty certificate for the Artifact!","TWN":"不！你看，那是標籤！那應該就是人造神器的保證書！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그럼, 저게 아티팩트라는 말이에요?","JPN":"じゃあ、あれがアーティファクトだってことですか？","ENG":"You mean, that's the Artifact?","TWN":"你的意思是，那個就是人造神器？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"도, 도망친다! 빨리 가서 잡아와요, 시영 씨!!","JPN":"に、逃げるわ！　早く捕まえて来てください、シノンさん！！","ENG":"I-it's running away! Quick, catch it, Shiyoung!","TWN":"牠，牠跑了！快把牠抓回來，時雨！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"어라, 괜찮겠어요? 제가 아티팩트를 손에 넣어도?","JPN":"あれ、いいんですか？　私がアーティファクトを手に入れても。","ENG":"Oh, are you sure you want me to get my hands on the Artifact first?","TWN":"呃，人造神器落到我手裡也沒關係嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그, 그건 좀 그렇지만…… 전 고양이를 만질 수 없단 말이에요!!","JPN":"そ、それはちょっとアレですけど……私、猫に触れないんです！！","ENG":"Th-that's a bit concerning, but... I can't touch cats!","TWN":"是，不太好……可是我對貓毛過敏！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"에휴, 하여간 까탈스럽기도 하셔라.","JPN":"はあ、ややこしい。","ENG":"Geez, so fussy.","TWN":"哀，你的毛還真多。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하하, 강제로 뺏긴 했는데, 이거 어째 돌려달라고 아우성인데요?","JPN":"ハハ、無理やり奪ってはきましたけど、なんだか返してほしいってうるさいですよ？","ENG":"Ha ha, I took it by force, but the cat's eager to get it back.","TWN":"哈哈，我從小貓那裡搶來了，但牠一直喵喵叫，好像是叫我還給牠的意思？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그런데 이거 대체 어떻게 여는 거지?","JPN":"でもこれ、いったいどうやって開けるんだろう？","ENG":"How do I open this thing, anyway?","TWN":"不過這是要怎麼打開？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"안 돼요. 고양이보다 사람이 먼저에요.","JPN":"ダメです。猫より人が先です。","ENG":"No. People come first, before cats.","TWN":"不行，人比貓重要。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"매정하셔라. 하긴 어차피 여기 계속 있으면 침식파 때문에 위험하니까 구조한 셈 칠까요?","JPN":"冷たいなあ。まあ、どうせずっとここにいても侵食波で危ないですから、救助したってことにしますか。","ENG":"So cold-hearted. Well, let's just say we rescued the cat since the Corruption ray would be dangerous for it.","TWN":"真是冷酷。不過一直待在這裡會受到侵蝕波影響，就當是我們救牠一命吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이게 그 보증서인가, 어디보자…….","JPN":"これがその保証書かぁ、どれどれ……","ENG":"So this is the warranty certificate. Let's see...","TWN":"這就是那個保證書嗎，讓我看看……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"여기까지 도달한 걸 축하한다, 2등…….","JPN":"ここまでよくたどり着いたな。おめでとう、2位……","ENG":"Congratulations on coming in second...","TWN":"恭喜你到達這裡，第二名……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이 아티팩트의 이름은 원숭이 손……. 소원을 이뤄주는 대신 그에 맞는 대가를 지불해야 한다……?","JPN":"このアーティファクトの名前はサルの手……願いを叶える代わりに、それ相応の対価を払わないといけない……？","ENG":"This Artifact is called Monkey's Paw... Your wish may be granted, for a price...?","TWN":"這個人造神器叫猴爪……它可以用來實現願望，但必須付出相對的代價……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이거 무슨 행운의 편지 같은 거 아니에요? 아무리 봐도 수상한데?","JPN":"これ、なんだか不幸の手紙みたいじゃないですか？　どう見ても怪しいですけど。","ENG":"Is this a chain letter or something? It sounds very shady.","TWN":"這不會是什麼漂流瓶之類的吧？總覺得很可疑？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아니요. 제가 들었던 정보랑 일치해요. 아티팩트가 틀림없어요, 그거.","JPN":"いいえ。私が聞いた情報と一致しています。アーティファクトに間違いありません。","ENG":"No. It's consistent with the intel I received. That's definitely an Artifact.","TWN":"不，這和我聽到的情報一致，那個肯定就是人造神器。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"흐음…… 그래요?","JPN":"ふーん……そうですか？","ENG":"Hmm... Is it?","TWN":"唔……是嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그래서 카린 양은 이 아티팩트를 어떻게 쓸 생각일까나?","JPN":"それで、カリンさんはこのアーティファクトをどう使う気なのかな？","ENG":"So, how are you planning to use this Artifact, Karin?","TWN":"那你準備怎麼使用這個人造神器？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그 꼼꼼한 카린 양이 이런 아티팩트에 집착하는 거 보면, 분명히 대가에 대한 대책이 있겠죠?","JPN":"几帳面なカリンさんがこんなアーティファクトに執着してるところを見ると、対価についても策は考えてあるんですよね？","ENG":"You must have a solution for the \\"price\\" if someone as meticulous as you is obsessing over this Artifact.","TWN":"像卡琳那麼細心的人會執著於這個人造神器，應該早就已經想好要如何應付所謂的代價吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"물론이죠. 저는 머릿속에 놀 생각만 가득한 누구와는 다르다고요.","JPN":"もちろんです。遊ぶことだけしか考えていない誰かさんとは違いますから。","ENG":"Of course. Unlike someone, my head isn't filled with how to spend my free time.","TWN":"當然，我可不像某人，滿腦子只想著玩。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"네? 그게 누구일까나? 저는 잘 모르겠는데요?","JPN":"ええ？　それって誰ですか？　全然心当たりがないなあ。","ENG":"Huh? I wonder who that is. I have no idea.","TWN":"哈哈哈？你是指誰？我怎麼有聽沒有懂？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_CROSSROAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"흥! 당연히 시영 씨죠, 여기 저 말고 시영 씨 밖에 더 있어요?","JPN":"フン！　もちろんシノンさんですよ。ここには私以外、シノンさんしかいないではないですか。","ENG":"Hmph! It's you! Who else is here?!","TWN":"哼！當然是你，這裡除了我以外就只有你。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"시영 씨라면, <color=#ffd34c>놀이 공원 같은 곳에서 실컷 놀고 싶다</color>같이 쓸데없는…….","JPN":"シノンさんなら、<color=#ffd34c>遊園地とかで思いっきり遊びたい</color>、みたいなくだらない……","ENG":"I'm sure your head is filled with useless thoughts like, \\"<color=#ffd34c>I want to go somewhere like a theme park,</color>\\" and–","TWN":"如果是時雨，一定會說什麼<color=#ffd34c>想在遊樂園盡情玩耍</color>這種沒用的……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_02"},{"id":"L48_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":" 응?","JPN":" うん？","ENG":"Oh?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"엇차, 드디어 열렸다!","JPN":"よいしょっと、やっと開いた！","ENG":"Phew, it's open!","TWN":"哇喔，打開咧！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"어, 어라? 빛이 나네?","JPN":"あ、あれ？　光ってる？","ENG":"H-huh? It's glowing!","TWN":"呃，哇？它在發光？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_02"},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"어?","JPN":"え？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"어, 어어……!? 멈춰요, 시영 씨!! 그 케이스 함부로 열 면……!!","JPN":"え、ええっ……！？　待ってください、シノンさん！！　そのケース、むやみに開けたら……！！","ENG":"Wha...?! Stop, Shiyoung! Don't open that bo–","TWN":"呃，呃呃……？！住手，時雨！不要隨便打開……！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"……그래서 눈을 떠보니, 유령의 집이었다?","JPN":"……そして目覚めてみると、お化け屋敷だったと？","ENG":"...And you woke up in this haunted house?","TWN":"……所以你一睜開眼，就發現自己在鬼屋裡？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_APHALLOWEEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"제가 그런 헛소리를 믿을 것 같습니까!?","JPN":"僕がそんなことを信じるとでも思っているのですか！？","ENG":"Did you think I'd fall for such nonsense?!","TWN":"你以為我會相信你的鬼話嗎？！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_APHALLOWEEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_APHALLOWEEN_NULL","text":{"KOREA":"믿기 힘든 건 맞지만, 사실이라고요!","JPN":"信じ難いのは事実ですけど、本当なんです！","ENG":"I know it's not very believable, but it's true!","TWN":"我知道這很難讓人相信，但我說的都是真的！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_APHALLOWEEN_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_APHALLOWEEN_NULL","text":{"KOREA":"그렇게 눈을 뜬 저는 관리국 스탭들의 배려로 이곳 고스트 하우스에서 일하게 되었지만…….","JPN":"そうして目覚めた私は、管理局スタッフの計らいでこのゴーストハウスで働けることになったのですが……","ENG":"I woke up, and started working here thanks to the generosity of the staff members of the Administration, but...","TWN":"當時多虧有管理局工作人員的關照，才能在這個鬼屋工作……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_APHALLOWEEN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_APHALLOWEEN_NULL","text":{"KOREA":"히, 히이익!!","JPN":"ひ、ひいいっ！！","ENG":"E-eeek!","TWN":"嗚，嗚嗚！！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KYLE_DELTA_APHALLOWEEN_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_APHALLOWEEN_NULL","text":{"KOREA":"여, 역시…… 유, 유령의 집은…… 좀…….","JPN":"や、やはり……お、お化け屋敷は……ちょっと……","ENG":"A-a... h-haunted house is... a bit...","TWN":"果，果然……鬼，鬼屋……有點……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KYLE_DELTA_APHALLOWEEN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_APHALLOWEEN_NULL","text":{"KOREA":"하지만 이곳에서 일하는 동안 당초 목표였던 관리국의 최신 기술력을 관찰할 수 있었어요.","JPN":"でもここで働く間に、当初の目的だった管理局の最新技術力を観察することができました。","ENG":"But I was able to observe the state-of-the-art technology of the Administration while working here.","TWN":"但在這裡工作的時候，我得以觀察到管理局的最新技術，那也是我當初的目的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_APHALLOWEEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_APHALLOWEEN_NULL","text":{"KOREA":"물론, 대부분은 제 능력으로도 이해할 수 없는 고차원의 기술이었지만요.","JPN":"もちろん、ほとんどは私の能力でも理解できない、ハイテクでしたけど。","ENG":"Of course, most of it was highly advanced, and I could not comprehend it, even with my abilities.","TWN":"當然，大部分的高端技術，單憑我的能力是根本無法理解的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_APHALLOWEEN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"가지가지 하는군요. 쓰레기 무단 투기에 이어서, 이번에는 산업 스파이입니까?","JPN":"呆れましたね。ゴミの不法投棄に、今度は産業スパイですか？","ENG":"It's always one thing after another. First, you illegally dispose of trash, and now you're engaging in industrial espionage?","TWN":"你還真忙，之前來這裡亂扔垃圾，現在又當起間諜？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_APHALLOWEEN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"제가 전에 말했었죠? 법정에서 당신들의 죗값을 치르게 하겠다고.","JPN":"前に言いましたよね。法廷であなたたちの罪を問うと。","ENG":"I told you. I'll make you pay for your crimes in court.","TWN":"我之前說過吧？我會讓你們在法庭伏法認罪。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"오늘이야말로 그때인 것 같군요.","JPN":"今日がその日のようですね。","ENG":"And it seems like today is that day.","TWN":"看來就是今天。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_APHALLOWEEN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_APHALLOWEEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KYLE_DELTA_APHALLOWEEN_NULL","text":{"KOREA":"좋아요. 법정에 서겠습니다. 하지만 제 선택에 후회는 없어요.","JPN":"いいでしょう。法廷に立ちます。ですが、自分の選択に悔いはありません。","ENG":"Very well. I'll see you in court. But I regret nothing from my decisions.","TWN":"好，我願意出庭。但我不後悔我的選擇。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_APHALLOWEEN_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"KYLE_DELTA_APHALLOWEEN_NULL","text":{"KOREA":"제발로 법정에 서서 죗값을 치룬 뒤, 사정을 설명하고 관리국에게 정식으로 기술원조를 부탁드려보겠습니다.","JPN":"自分の足で法廷に立って罪を償った後に、事情を説明して管理局に正式な技術援助を頼んでみます。","ENG":"I'll go to court, pay for my crimes, explain the situation, and ask the Administration for their official technical aid.","TWN":"我會親自出庭接受審判，然後說明情況，並請求管理局正式進行技術援助。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_APHALLOWEEN_NULL","face":"UNIT_PRIDE"}}}},{"id":"L32_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"흥, 지금까지의 당신의 행동이 썩 마음에 들지는 않지만…….","JPN":"フン、今までのあなたの行動はあまり気に入りませんが……","ENG":"Hmph, I don't really like what you've done so far...","TWN":"哼，雖說我不是很滿意你一直以來的所作所為……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_APHALLOWEEN_NULL","face":"UNIT_PRIDE"}}}},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"뭐, 좋습니다. 군인으로서의 최소한의 책임감만큼은 인정해드리죠.","JPN":"まあ、いいでしょう。軍人としての最低限の責任感だけは認めてあげます。","ENG":"But, very well. I'll admit, you have the minimal amount of responsibility any soldier should have.","TWN":"好吧，我承認你有身為軍人的那麼一絲絲責任感。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KYLE_DELTA_APHALLOWEEN_NULL","face":"UNIT_PRIDE"}}}},{"id":"L38_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저 대신 당신이 이 <color=#ffd34c>유니폼</color>을 스태프분께 전해주세요.","JPN":"私に代わって、この<color=#ffd34c>ユニフォーム</color>をスタッフの方に渡してもらえますか。","ENG":"Please hand this <color=#ffd34c>uniform</color> to a staff member for me.","TWN":"另外，請替我把這個<color=#ffd34c>制服</color>交還給工作人員。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L39_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"알겠습니다, 그럼 가죠.","JPN":"わかりました。行きましょう。","ENG":"Understood. Now, let's go.","TWN":"好，我們走吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이제 그만 좀 하자니까, 실비아. 벌써 1시간 째야.","JPN":"もういいだろ、シルビア。探し始めて1時間だぞ。","ENG":"C'mon, Sylvia. It's been an hour.","TWN":"到此為止吧，希爾維亞，我們都找一個多小時了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"부, 분명히 이쪽으로 왔었는데……? 대체 그 빨간 망토는 어디로…….","JPN":"た、確かにこっちに来たのに……あの赤ずきん、いったいどこに……","ENG":"I-I'm sure she came this way... Where did that Red Riding Hood go...?","TWN":"我，我明明看到她往這邊來啦……？那個紅色披風到底去哪啦……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"어?","JPN":"え？","ENG":"Huh?","TWN":"呃！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저…… 사람은……!?","JPN":"あの……人は……！？","ENG":"That's...!","TWN":"那……那個人是……？！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"어!? 카일!?","JPN":"あっ！？　カイル！？","ENG":"Oh! Kyle?!","TWN":"咦？！凱爾？！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"아! 실비아 씨, 대령님. 때마침 잘 왔습니다.","JPN":"あ！　シルビアさん、大佐。ちょうどいいところに。","ENG":"Ah! Sylvia, Colonel. Good timing.","TWN":"喔！希爾維亞，上校，你們來得正好。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"지난 번에 연구 기지를 무단으로 습격한 범인의 신병을 확보했습니다.","JPN":"この前研究基地を無断襲撃した犯人の身柄を確保しました。","ENG":"I've apprehended the culprit that ambushed our research facility.","TWN":"我抓到了上次無故襲擊研究基地的犯人。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"응? 범인? 무슨 소리를 하는 거야 카일?","JPN":"うん？　犯人？　何を言ってるんだ、カイル？","ENG":"Huh? Culprit? What are you talking about, Kyle?","TWN":"嗯？犯人？你在說什麼，凱爾？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"여기에 너 외에 누가 있다는 거야?","JPN":"ここにはお前しかいないぞ。","ENG":"There's no one else here but you.","TWN":"這裡除了你以外，還有其他人嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Excuse me?","TWN":"什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 그새 어디갔지?","JPN":"な、何だ？　いつの間に消えたんだ？","ENG":"W-what? Where did she go?","TWN":"怎，怎麼回事？人跑哪去了？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"설마, 도주한 건가!? 제길, 또 당했군요!","JPN":"まさか、逃走を！？　くそ、またやられてしまいました！","ENG":"Did she run away?! Dammit, she got me again!","TWN":"不會是逃跑了吧？！可惡，又被騙了！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"……어, 어어? 카일!!","JPN":"……え、ええ？　カイル！！","ENG":"...Huh? Oh! Kyle!","TWN":"……呃，呃呃？凱爾！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"네가 들고 있는 그거? 빨간 망토 아니야?","JPN":"アンタが持ってるそれ！　赤ずきんじゃないの？","ENG":"That thing you're holding, isn't that a costume of Red Riding Hood?","TWN":"你手上拿著的，是紅色披風嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"아, 이건 범인이 저에게 남긴 유류품입니다.","JPN":"あ、これは犯人が残した遺留品です。","ENG":"Ah, this is something the culprit left behind.","TWN":"喔，這是犯人留下來的東西。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"범인은 이곳에서 위장 취업 중이었어요.","JPN":"犯人はここに偽装就職中でした。","ENG":"The culprit was working here undercover.","TWN":"犯人曾偽裝身份在這裡工作。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"위장 취업?","JPN":"偽装就職？","ENG":"Working undercover?","TWN":"偽裝身份？工作？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"흐으음~ 그래, 그렇구나. 그런 설정이었구나?","JPN":"ふうん～そう、なるほど。そういう設定だったのね？","ENG":"Hmmm! Okay, all right. \\"Working undercover.\\" That's your backstory.","TWN":"嗯嗯嗯～是喔，這樣喔，原來是這種人設喔？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"네? 설정? 무슨 설정을 말하는 겁니까?","JPN":"はい？　設定？　何の設定のことですか？","ENG":"Huh? Backstory? What are you talking about?","TWN":"什麼？人設？你在說什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"……크, 크흠. 흠!! 그런 취미를 가지고 있었다니, 의외인 걸 카일?","JPN":"……こ、こほん。ふむ！！　そういった趣味を持っているとは、意外だな。カイル。","ENG":"...Ahem! Errhm! I'm surprised you had this kind of hobby, Kyle.","TWN":"……咳，咳咳。咳！你居然有那種嗜好，真令人意外，凱爾？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하지만 걱정 말라구. 나는 부하의 취향 정도는 존중해주는 편이니까.","JPN":"だが、心配するな。俺は部下の好みは尊重してやる方だから。","ENG":"But don't worry. I'm pretty accepting of my subordinates' tastes.","TWN":"但不用擔心，我一向很尊重屬性的興趣的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"취미? 취향? 대체 무슨 말씀을 하는 겁니까, 대령님?","JPN":"趣味？　好み？　いったい何のことですか、大佐。","ENG":"Hobby? Taste? What do you mean, Colonel?","TWN":"嗜好？興趣？你到底在說什麼，上校？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"……대령님? 실비아 씨?","JPN":"……大佐？　シルビアさん？","ENG":"...Colonel? Sylvia?","TWN":"……上校？希爾維亞？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"역시 그랬어…….","JPN":"やっぱり……","ENG":"Of course...","TWN":"果然……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L36_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저쪽 세계에서는 살아 계시는구나…….","JPN":"あちらの世界では生きているんですね……","ENG":"He's alive in that world...","TWN":"在這個世界，他還活著……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"대령님…….","JPN":"大佐……","ENG":"Colonel...","TWN":"上校……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};